import SwiftUI

/// High-resolution pixel art sprites (512x512). Palette + base64 encoded.
struct ClaudeSpriteView: View {
    let state: TapState

    var body: some View {
        staticSprite
    }

    private var staticSprite: some View {
        Canvas { ctx, size in
            let grid = 512
            let data = pixelBytes(for: state)
            let palette = paletteFor(state: state)
            guard !data.isEmpty else { return }
            let w = size.width / CGFloat(grid)
            let h = size.height / CGFloat(grid)
            for y in 0..<grid {
                for x in 0..<grid {
                    let idx = Int(data[y * grid + x])
                    if idx == 0 { continue }
                    let c = palette[idx]
                    let rect = CGRect(x: CGFloat(x) * w, y: CGFloat(y) * h, width: w + 0.5, height: h + 0.5)
                    ctx.fill(Path(rect), with: .color(Color(red: c.r, green: c.g, blue: c.b)))
                }
            }
        }
    }

    private func pixelBytes(for state: TapState) -> [UInt8] {
        let b64: String
        switch state {
        case .idle: b64 = Self.data_idle
        case .working: b64 = Self.data_working
        case .done: b64 = Self.data_done
        case .needsApproval: b64 = Self.data_approval
        }
        return Array(Data(base64Encoded: b64) ?? Data())
    }

    private func paletteFor(state: TapState) -> [Pixel] {
        switch state {
        case .idle: return Self.palette_idle
        case .working: return Self.palette_working
        case .done: return Self.palette_done
        case .needsApproval: return Self.palette_approval
        }
    }

